// PATCH: Cover output routing outside the novel command set so --deliver captures local analytics output.
func TestAnalyticsDeliverWritesFile(t *testing.T) {
	dbPath := filepath.Join(t.TempDir(), "data.db")
	outPath := filepath.Join(t.TempDir(), "analytics.json")
	stdout, stderr, err := executeForTest(t, "analytics", "--db", dbPath, "--json", "--deliver", "file:"+outPath)
	if err != nil {
		t.Fatalf("Execute: %v", err)
	}
	if stderr != "" {
		t.Fatalf("stderr = %q", stderr)
	}
	if !json.Valid([]byte(stdout)) {
		t.Fatalf("stdout = %q, want JSON", stdout)
	}
	data, err := os.ReadFile(outPath)
	if err != nil {
		t.Fatalf("read delivered file: %v", err)
	}
	if !json.Valid(data) {
		t.Fatalf("delivered file = %q, want JSON", string(data))
	}
}

// PATCH: idempotent no-op JSON originates in error classification, outside Cobra writers.
func TestWriteNoopMirrorsDeliverBuffer(t *testing.T) {
	oldStdout := os.Stdout
	r, w, err := os.Pipe()
	if err != nil {
		t.Fatalf("pipe stdout: %v", err)
	}
	os.Stdout = w
	t.Cleanup(func() {
		os.Stdout = oldStdout
		_ = r.Close()
	})

	flags := &rootFlags{asJSON: true, deliverBuf: &bytes.Buffer{}}
	if err := writeNoop(flags, "already_exists", "already exists"); err != nil {
		t.Fatalf("writeNoop: %v", err)
	}
	if err := w.Close(); err != nil {
		t.Fatalf("close stdout pipe: %v", err)
	}
	os.Stdout = oldStdout

	stdout, err := io.ReadAll(r)
	if err != nil {
		t.Fatalf("read stdout pipe: %v", err)
	}
	if !json.Valid(stdout) {
		t.Fatalf("stdout = %q, want JSON", string(stdout))
	}
	if flags.deliverBuf.String() != string(stdout) {
		t.Fatalf("deliver buffer = %q, want stdout %q", flags.deliverBuf.String(), string(stdout))
	}
}

